import React from 'react';
import './styles.css';

const cards = [
  { id: 1, title: 'Design', desc: 'Create beautiful interfaces' },
  { id: 2, title: 'Develop', desc: 'Build robust applications' },
  { id: 3, title: 'Deploy', desc: 'Ship to production' },
  { id: 4, title: 'Monitor', desc: 'Track performance' },
  { id: 5, title: 'Iterate', desc: 'Improve continuously' },
  { id: 6, title: 'Scale', desc: 'Grow with confidence' },
];

export default function App() {
  return (
    <div className="grid" data-testid="grid">
      {cards.map(c => (
        <div key={c.id} className="grid__card" data-testid={`card-${c.id}`}>
          <h3 className="grid__card-title">{c.title}</h3>
          <p className="grid__card-desc">{c.desc}</p>
        </div>
      ))}
    </div>
  );
}

