import { render, screen } from '@testing-library/react';
import '@testing-library/jest-dom';
import App from './App';

describe('Responsive Card Grid', () => {
  beforeEach(() => {
    render(<App />);
  });

  it('grid uses CSS Grid', () => {
    const grid = screen.getByTestId('grid');
    expect(getComputedStyle(grid).display).toBe('grid');
  });

  it('grid has gap', () => {
    const grid = screen.getByTestId('grid');
    const styles = getComputedStyle(grid);
    expect(styles.gap).toBe('1.5rem');
  });

  it('grid has padding', () => {
    const grid = screen.getByTestId('grid');
    const styles = getComputedStyle(grid);
    expect(styles.padding).toBe('2rem');
  });

  it('card has white background', () => {
    const card = screen.getByTestId('card-1');
    expect(getComputedStyle(card).backgroundColor).toBe('rgb(255, 255, 255)');
  });

  it('card has border-radius', () => {
    const card = screen.getByTestId('card-1');
    expect(getComputedStyle(card).borderRadius).toBe('0.5rem');
  });

  it('card has border', () => {
    const card = screen.getByTestId('card-1');
    const styles = getComputedStyle(card);
    expect(styles.borderStyle).toBe('solid');
  });

  it('card has padding', () => {
    const card = screen.getByTestId('card-1');
    expect(getComputedStyle(card).padding).toBe('1rem');
  });

  it('renders all 6 cards', () => {
    for (let i = 1; i <= 6; i++) {
      expect(screen.getByTestId(`card-${i}`)).toBeInTheDocument();
    }
  });
});

